oldWay:
/* Old float-based 3-column grid */
.item {
  float: left;
  width: calc(33.333% - 14px);
  margin-right: 20px;
}
.item:nth-child(3n) {
  margin-right: 0;
}
/* Don't forget the clearfix hack... */

startingCSS:
.container {
  display: grid;
  gap: 1rem;
}

.item {
  background: #a855f7;
  color: white;
  padding: 2rem;
  border-radius: 8px;
  text-align: center;
  font-size: 1.25rem;
  font-weight: 600;
}

alternatives.css:
.container {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
  gap: 1rem;
}
